const url = $json.video_url || '';
const m = url.match(/[?&]v=([a-zA-Z0-9_-]{11})/) || url.match(/youtu\.be\/([a-zA-Z0-9_-]{11})/);
if (!m) throw new Error('Could not parse video_id');
return [{ ...$json, video_id: m[1] }];

const html = $json.body || $json.data || '';
const lines = [];
for (const match of html.matchAll(/<div class=\"transcript-text\">([\s\S]*?)<\/div>/g)) {
  lines.push(match[1].replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim());
}
const transcript = lines.filter(Boolean).join('\n');
if (!transcript) throw new Error('Transcript extraction failed; switch provider or ASR fallback.');
return [{ ...$json, transcript, transcript_source: 'ytscribe_html_extract' }];

const text = $json.transcript;
const chunkSize = 6000;
const out = [];
for (let i = 0; i < text.length; i += chunkSize) {
  out.push({ ...$json, chunk_index: out.length, chunk_text: text.slice(i, i + chunkSize) });
}
return out;
